    let mut failure_trace = None;
    for seed in 0..100 {
        tracing::debug!(seed, "Trying seed");

        let recorder = TraceRecorder::new(RecorderConfig::default());
        let lab = LabRuntimeBuilder::new()
            .rng_seed(seed)
            .record_trace(recorder)
            .build();

        let result = lab.run(|cx| async {
